public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // в”Ђв”Ђ Full constructor в”Ђв”Ђ
        try {
            Monster dragon = new Monster("Dragon", 200, 50);
            check("Full constructor вЂ” name",
                  "Dragon", dragon.name);
        } catch (Exception e) { fail("Full constructor вЂ” name", e); }

        try {
            Monster dragon = new Monster("Dragon", 200, 50);
            check("Full constructor вЂ” health",
                  "200", String.valueOf(dragon.health));
        } catch (Exception e) { fail("Full constructor вЂ” health", e); }

        try {
            Monster dragon = new Monster("Dragon", 200, 50);
            check("Full constructor вЂ” attackPower",
                  "50", String.valueOf(dragon.attackPower));
        } catch (Exception e) { fail("Full constructor вЂ” attackPower", e); }

        // в”Ђв”Ђ Name-only constructor (defaults) в”Ђв”Ђ
        try {
            Monster goblin = new Monster("Goblin");
            check("Name-only constructor вЂ” name",
                  "Goblin", goblin.name);
        } catch (Exception e) { fail("Name-only constructor вЂ” name", e); }

        try {
            Monster goblin = new Monster("Goblin");
            check("Name-only constructor вЂ” default health",
                  "50", String.valueOf(goblin.health));
        } catch (Exception e) { fail("Name-only constructor вЂ” default health", e); }

        try {
            Monster goblin = new Monster("Goblin");
            check("Name-only constructor вЂ” default attackPower",
                  "10", String.valueOf(goblin.attackPower));
        } catch (Exception e) { fail("Name-only constructor вЂ” default attackPower", e); }

        // в”Ђв”Ђ roar() в”Ђв”Ђ
        try {
            Monster dragon = new Monster("Dragon", 200, 50);
            check("roar() вЂ” Dragon",
                  "Dragon roars with power 50!",
                  dragon.roar());
        } catch (Exception e) { fail("roar() вЂ” Dragon", e); }

        try {
            Monster goblin = new Monster("Goblin");
            check("roar() вЂ” Goblin (defaults)",
                  "Goblin roars with power 10!",
                  goblin.roar());
        } catch (Exception e) { fail("roar() вЂ” Goblin", e); }

        // в”Ђв”Ђ status() в”Ђв”Ђ
        try {
            Monster dragon = new Monster("Dragon", 200, 50);
            check("status() вЂ” Dragon",
                  "Dragon [HP=200, ATK=50]",
                  dragon.status());
        } catch (Exception e) { fail("status() вЂ” Dragon", e); }

        try {
            Monster goblin = new Monster("Goblin");
            check("status() вЂ” Goblin (defaults)",
                  "Goblin [HP=50, ATK=10]",
                  goblin.status());
        } catch (Exception e) { fail("status() вЂ” Goblin", e); }

        // в”Ђв”Ђ Two objects are independent в”Ђв”Ђ
        try {
            Monster a = new Monster("Orc", 80, 15);
            Monster b = new Monster("Slime", 10, 2);
            boolean independent = !a.name.equals(b.name)
                               && a.health != b.health;
            check("Two Monsters hold independent data",
                  "true", String.valueOf(independent));
        } catch (Exception e) { fail("Independent instances", e); }

        // в”Ђв”Ђ Verify both constructors exist (reflection) в”Ђв”Ђ
        try {
            java.lang.reflect.Constructor<?>[] ctors = Monster.class.getDeclaredConstructors();
            check("Monster has 2 constructors (overloading)",
                  "true", String.valueOf(ctors.length >= 2));
        } catch (Exception e) { fail("Constructor count", e); }
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e.getMessage()); failed++;
    }
}
